// // This module compares two 4-bit binary numbers and outputs if the first number is less than, greater than, or equal to the second number.
module comparator_4bit(
    input [3:0] a, b,
    output a_gt_b,
    output a_lt_b,
    output a_eq_b);

    assign a_gt_b = (a > b);
    assign a_lt_b = (a < b);
    assign a_eq_b = (a == b);
endmodule
